import { Component, OnInit } from '@angular/core';
import { TranslateService } from '@ngx-translate/core';
import { SummaryService, YearlySummary } from '../../services/summary.service';

interface SummaryData {
  totalRevenue: number;
  totalExpenses: number;
  totalInvestments: number;
  netProfit: number;
  ownerShare: number;
  partnerShare: number;
}

interface MonthlyData {
  month: string;
  year: number;
  revenue: number;
  expenses: number;
  investments: number;
  profit: number;
}

interface YearlyData {
  year: number;
  revenue: number;
  expenses: number;
  investments: number;
  profit: number;
  months: MonthlyData[];
}

@Component({
  selector: 'app-reports',
  templateUrl: './reports.component.html',
  styleUrls: ['./reports.component.css']
})
export class ReportsComponent implements OnInit {
  summary: SummaryData | null = null;
  yearlyData: YearlyData[] = [];
  selectedYear: number = 2026;
  selectedMonth: number = 3;
  viewMode: 'yearly' | 'monthly' = 'monthly';
  availableYears: number[] = [];
  availableMonths: string[] = [];
  loading = false;
  error: string | null = null;

  constructor(
    private summaryService: SummaryService,
    private translate: TranslateService
  ) {}

  ngOnInit(): void {
    this.generateAvailableYears();
    this.loadSummary();
    this.loadMonths();
    
    // Load data based on initial view mode
    if (this.viewMode === 'monthly') {
      this.loadMonthlyData();
    } else {
      this.loadYearlyData();
    }
    
    this.translate.onLangChange.subscribe(() => {
      this.loadMonths();
    });
  }

  loadMonths(): void {
    this.availableMonths = [
      this.translate.instant('MONTHS.JANUARY'),
      this.translate.instant('MONTHS.FEBRUARY'),
      this.translate.instant('MONTHS.MARCH'),
      this.translate.instant('MONTHS.APRIL'),
      this.translate.instant('MONTHS.MAY'),
      this.translate.instant('MONTHS.JUNE'),
      this.translate.instant('MONTHS.JULY'),
      this.translate.instant('MONTHS.AUGUST'),
      this.translate.instant('MONTHS.SEPTEMBER'),
      this.translate.instant('MONTHS.OCTOBER'),
      this.translate.instant('MONTHS.NOVEMBER'),
      this.translate.instant('MONTHS.DECEMBER')
    ];
  }

  generateAvailableYears(): void {
    const currentYear = new Date().getFullYear();
    this.availableYears = [];
    for (let year = currentYear - 5; year <= currentYear + 1; year++) {
      this.availableYears.push(year);
    }
  }

  loadSummary(): void {
    // Calculate summary from yearlyData when available
    if (this.yearlyData.length > 0) {
      const data = this.yearlyData[0];
      const netProfit = data.profit;
      
      this.summary = {
        totalRevenue: data.revenue,
        totalExpenses: data.expenses,
        totalInvestments: data.investments,
        netProfit: netProfit,
        ownerShare: netProfit > 0 ? netProfit * 0.7 : 0,
        partnerShare: netProfit > 0 ? netProfit * 0.3 : 0
      };
    } else {
      this.summary = {
        totalRevenue: 0,
        totalExpenses: 0,
        totalInvestments: 0,
        netProfit: 0,
        ownerShare: 0,
        partnerShare: 0
      };
    }
  }

  loadYearlyData(): void {
    this.loading = true;
    this.error = null;

    this.summaryService.getYearlySummary(this.selectedYear).subscribe({
      next: (data: any) => {
        if (data) {
          // Convert monthly breakdown if available
          const months: MonthlyData[] = [];
          if (data.months && data.months.length > 0) {
            data.months.forEach((m: any) => {
              const monthIndex = parseInt(m.month) - 1;
              months.push({
                month: this.availableMonths[monthIndex],
                year: parseInt(m.year),
                revenue: parseFloat(m.total_revenue_ll || '0'),
                expenses: parseFloat(m.total_expenses_ll || '0'),
                investments: 0,
                profit: parseFloat(m.balance_ll || '0')
              });
            });
          }

          this.yearlyData = [{
            year: parseInt(data.year),
            revenue: parseFloat(data.total_revenue_ll || '0'),
            expenses: parseFloat(data.total_expenses_ll || '0'),
            investments: 0,
            profit: parseFloat(data.balance_ll || '0'),
            months: months
          }];
          
          // Update summary with actual data
          this.loadSummary();
        } else {
          this.yearlyData = [];
        }
        this.loading = false;
      },
      error: (error) => {
        this.error = 'Failed to load yearly data';
        this.loading = false;
        console.error('Error loading yearly data:', error);
      }
    });
  }

  loadMonthlyData(): void {
    this.loading = true;
    this.error = null;

    console.log('Loading monthly data for:', this.selectedYear, 'month:', this.selectedMonth + 1);
    
    this.summaryService.getMonthlySummary(this.selectedYear, this.selectedMonth + 1).subscribe({
      next: (data: any) => {
        console.log('Monthly data received:', data);
        if (data) {
          // Store monthly data in yearlyData structure for compatibility
          this.yearlyData = [{
            year: this.selectedYear,
            revenue: parseFloat(data.total_revenue_ll || '0'),
            expenses: parseFloat(data.total_expenses_ll || '0'),
            investments: 0,
            profit: parseFloat(data.balance_ll || '0'),
            months: [{
              month: this.availableMonths[this.selectedMonth],
              year: this.selectedYear,
              revenue: parseFloat(data.total_revenue_ll || '0'),
              expenses: parseFloat(data.total_expenses_ll || '0'),
              investments: 0,
              profit: parseFloat(data.balance_ll || '0')
            }]
          }];
          console.log('Processed yearlyData:', this.yearlyData);
          
          // Update summary with actual data
          this.loadSummary();
        } else {
          console.log('No data returned');
          this.yearlyData = [];
        }
        this.loading = false;
      },
      error: (error) => {
        this.error = 'Failed to load monthly data';
        this.loading = false;
        console.error('Error loading monthly data:', error);
      }
    });
  }

  generateMonthlyData(summary: SummaryData): MonthlyData[] {
    const months: MonthlyData[] = [];
    // Distribute the totals across months for demonstration
    // In a real implementation, this would come from actual monthly aggregations
    for (let i = 0; i < 12; i++) {
      const monthlyRevenue = Math.round(summary.totalRevenue / 12);
      const monthlyExpenses = Math.round(summary.totalExpenses / 12);
      const monthlyInvestments = Math.round(summary.totalInvestments / 12);
      const monthlyProfit = monthlyRevenue - monthlyExpenses;

      months.push({
        month: this.availableMonths[i],
        year: this.selectedYear,
        revenue: monthlyRevenue,
        expenses: monthlyExpenses,
        investments: monthlyInvestments,
        profit: monthlyProfit
      });
    }
    return months;
  }

  onYearChange(): void {
    if (this.viewMode === 'monthly') {
      this.loadMonthlyData();
    } else {
      this.loadYearlyData();
    }
  }

  onMonthChange(): void {
    if (this.viewMode === 'monthly') {
      this.loadMonthlyData();
    }
  }

  onViewModeChange(): void {
    if (this.viewMode === 'monthly') {
      this.loadMonthlyData();
    } else {
      this.loadYearlyData();
    }
  }

  getCurrentYearData(): YearlyData | null {
    return this.yearlyData.length > 0 ? this.yearlyData[0] : null;
  }

  getCurrentMonthData(): MonthlyData | null {
    const yearData = this.getCurrentYearData();
    if (yearData && yearData.months && yearData.months.length > 0) {
      return yearData.months[0];
    }
    return null;
  }

  getProfitMargin(amount: number, total: number): number {
    return total > 0 ? (amount / total) * 100 : 0;
  }
}
<div class="reports-container">
  <div class="header">
    <h1>{{ 'REPORTS.TITLE' | translate }}</h1>
    <a routerLink="/dashboard" class="btn btn-secondary">{{ 'NAV.DASHBOARD' | translate }}</a>
  </div>

  <!-- Controls -->
  <div class="controls-section">
    <div class="control-group">
      <label>{{ 'FILTERS.VIEW_MODE' | translate }}:</label>
      <select [(ngModel)]="viewMode" (change)="onViewModeChange()" class="control-select">
        <option value="yearly">{{ 'REPORTS.YEARLY_SUMMARY' | translate }}</option>
        <option value="monthly">{{ 'REPORTS.MONTHLY_SUMMARY' | translate }}</option>
      </select>
    </div>

    <div class="control-group">
      <label>{{ 'FILTERS.YEAR' | translate }}:</label>
      <select [(ngModel)]="selectedYear" (ngModelChange)="onYearChange()" class="control-select">
        <option *ngFor="let year of availableYears" [ngValue]="year">{{year}}</option>
      </select>
    </div>

    <div class="control-group" *ngIf="viewMode === 'monthly'">
      <label>{{ 'FILTERS.MONTH' | translate }}:</label>
      <select [(ngModel)]="selectedMonth" (ngModelChange)="onMonthChange()" class="control-select">
        <option *ngFor="let month of availableMonths; let i = index" [ngValue]="i">{{month}}</option>
      </select>
    </div>
  </div>

  <!-- Error Message -->
  <div class="error-message" *ngIf="error">
    {{error}}
  </div>

  <!-- Loading Indicator -->
  <div class="loading" *ngIf="loading">
    {{ 'COMMON.LOADING' | translate }}...
  </div>

  <!-- Overall Summary -->
  <div class="summary-section" *ngIf="summary && !loading">
    <h2>{{ 'REPORTS.PROFIT_LOSS' | translate }}</h2>
    <div class="summary-cards">
      <div class="summary-card revenue">
        <div class="card-icon">💰</div>
        <div class="card-content">
          <div class="card-title">{{ 'DASHBOARD.TOTAL_REVENUE' | translate }}</div>
          <div class="card-value">${{summary.totalRevenue | number:'1.2-2'}}</div>
        </div>
      </div>

      <div class="summary-card expenses">
        <div class="card-icon">💸</div>
        <div class="card-content">
          <div class="card-title">{{ 'DASHBOARD.TOTAL_EXPENSES' | translate }}</div>
          <div class="card-value">${{summary.totalExpenses | number:'1.2-2'}}</div>
        </div>
      </div>

      <div class="summary-card investments">
        <div class="card-icon">📈</div>
        <div class="card-content">
          <div class="card-title">{{ 'INVESTMENTS.TOTAL_INVESTMENTS' | translate }}</div>
          <div class="card-value">${{summary.totalInvestments | number:'1.2-2'}}</div>
        </div>
      </div>

      <div class="summary-card profit" [class]="summary.netProfit >= 0 ? 'positive' : 'negative'">
        <div class="card-icon">{{summary.netProfit >= 0 ? '📊' : '📉'}}</div>
        <div class="card-content">
          <div class="card-title">{{ 'DASHBOARD.NET_PROFIT' | translate }}</div>
          <div class="card-value">${{summary.netProfit | number:'1.2-2'}}</div>
        </div>
      </div>
    </div>

    <!-- Profit Distribution -->
    <div class="distribution-section">
      <h3>{{ 'REPORTS.SHARES_DISTRIBUTION' | translate }}</h3>
      <div class="distribution-cards">
        <div class="distribution-card">
          <div class="distribution-label">{{ 'DASHBOARD.FIRST_SHARE' | translate }} (70%)</div>
          <div class="distribution-value">${{summary.ownerShare | number:'1.2-2'}}</div>
        </div>
        <div class="distribution-card">
          <div class="distribution-label">{{ 'DASHBOARD.SECOND_SHARE' | translate }} (30%)</div>
          <div class="distribution-value">${{summary.partnerShare | number:'1.2-2'}}</div>
        </div>
      </div>
    </div>
  </div>

  <!-- Yearly Dashboard -->
  <div class="dashboard-section" *ngIf="viewMode === 'yearly' && getCurrentYearData() as yearData">
    <h2>{{yearData.year}} {{ 'REPORTS.YEARLY_SUMMARY' | translate }}</h2>

    <div class="yearly-metrics">
      <div class="metric-card">
        <h3>{{ 'DASHBOARD.TOTAL_REVENUE' | translate }}</h3>
        <div class="metric-value">${{yearData.revenue | number:'1.2-2'}}</div>
      </div>
      <div class="metric-card">
        <h3>{{ 'DASHBOARD.TOTAL_EXPENSES' | translate }}</h3>
        <div class="metric-value">${{yearData.expenses | number:'1.2-2'}}</div>
      </div>
      <div class="metric-card">
        <h3>{{ 'INVESTMENTS.TOTAL_INVESTMENTS' | translate }}</h3>
        <div class="metric-value">${{yearData.investments | number:'1.2-2'}}</div>
      </div>
      <div class="metric-card" [class]="yearData.profit >= 0 ? 'positive' : 'negative'">
        <h3>{{ 'DASHBOARD.NET_PROFIT' | translate }}</h3>
        <div class="metric-value">${{yearData.profit | number:'1.2-2'}}</div>
      </div>
    </div>

    <!-- Monthly Breakdown Table -->
    <div class="monthly-table-section">
      <h3>{{ 'REPORTS.MONTHLY_SUMMARY' | translate }}</h3>
      <div class="table-container">
        <table class="monthly-table">
          <thead>
            <tr>
              <th>{{ 'FILTERS.MONTH' | translate }}</th>
              <th>{{ 'REVENUE.TITLE' | translate }}</th>
              <th>{{ 'EXPENSES.TITLE' | translate }}</th>
              <th>{{ 'INVESTMENTS.TITLE' | translate }}</th>
              <th>{{ 'DASHBOARD.NET_PROFIT' | translate }}</th>
              <th>{{ 'COMMON.TOTAL' | translate }}</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let month of yearData.months">
              <td>{{month.month}}</td>
              <td class="amount-cell">${{month.revenue | number:'1.2-2'}}</td>
              <td class="amount-cell">${{month.expenses | number:'1.2-2'}}</td>
              <td class="amount-cell">${{month.investments | number:'1.2-2'}}</td>
              <td class="amount-cell" [class]="month.profit >= 0 ? 'positive' : 'negative'">
                ${{month.profit | number:'1.2-2'}}
              </td>
              <td class="percentage-cell">
                {{getProfitMargin(month.profit, month.revenue) | number:'1.1-1'}}%
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </div>

  <!-- Monthly Dashboard -->
  <div class="dashboard-section" *ngIf="viewMode === 'monthly' && getCurrentMonthData() as monthData">
    <h2>{{availableMonths[selectedMonth]}} {{selectedYear}} {{ 'REPORTS.MONTHLY_SUMMARY' | translate }}</h2>

    <div class="monthly-metrics">
      <div class="metric-card">
        <h3>{{ 'DASHBOARD.TOTAL_REVENUE' | translate }}</h3>
        <div class="metric-value">${{monthData.revenue | number:'1.2-2'}}</div>
      </div>
      <div class="metric-card">
        <h3>{{ 'DASHBOARD.TOTAL_EXPENSES' | translate }}</h3>
        <div class="metric-value">${{monthData.expenses | number:'1.2-2'}}</div>
      </div>
      <div class="metric-card">
        <h3>{{ 'INVESTMENTS.TOTAL_INVESTMENTS' | translate }}</h3>
        <div class="metric-value">${{monthData.investments | number:'1.2-2'}}</div>
      </div>
      <div class="metric-card" [class]="monthData.profit >= 0 ? 'positive' : 'negative'">
        <h3>{{ 'DASHBOARD.NET_PROFIT' | translate }}</h3>
        <div class="metric-value">${{monthData.profit | number:'1.2-2'}}</div>
      </div>
    </div>

    <!-- Performance Indicators -->
    <div class="performance-section">
      <h3>{{ 'REPORTS.PROFIT_LOSS' | translate }}</h3>
      <div class="indicators-grid">
        <div class="indicator-card">
          <div class="indicator-label">{{ 'EXPENSES.TITLE' | translate }}</div>
          <div class="indicator-value">
            {{getProfitMargin(monthData.expenses, monthData.revenue) | number:'1.1-1'}}%
          </div>
          <div class="indicator-desc">{{ 'EXPENSES.TITLE' | translate }} / {{ 'REVENUE.TITLE' | translate }}</div>
        </div>
        <div class="indicator-card">
          <div class="indicator-label">{{ 'INVESTMENTS.TITLE' | translate }}</div>
          <div class="indicator-value">
            {{getProfitMargin(monthData.investments, monthData.revenue) | number:'1.1-1'}}%
          </div>
          <div class="indicator-desc">{{ 'INVESTMENTS.TITLE' | translate }} / {{ 'REVENUE.TITLE' | translate }}</div>
        </div>
        <div class="indicator-card">
          <div class="indicator-label">{{ 'DASHBOARD.NET_PROFIT' | translate }}</div>
          <div class="indicator-value" [class]="monthData.profit >= 0 ? 'positive' : 'negative'">
            {{getProfitMargin(monthData.profit, monthData.revenue) | number:'1.1-1'}}%
          </div>
          <div class="indicator-desc">{{ 'DASHBOARD.NET_PROFIT' | translate }} / {{ 'REVENUE.TITLE' | translate }}</div>
        </div>
        <div class="indicator-card">
          <div class="indicator-label">ROI</div>
          <div class="indicator-value">
            {{monthData.investments > 0 ? ((monthData.profit / monthData.investments) * 100) : 0 | number:'1.1-1'}}%
          </div>
          <div class="indicator-desc">{{ 'DASHBOARD.NET_PROFIT' | translate }} / {{ 'INVESTMENTS.TITLE' | translate }}</div>
        </div>
      </div>
    </div>
  </div>
</div>
